B.io=new A.aw(983713,"MaterialIcons",!1)
B.asT=new A.ir("Cerebral Edema","Cytotoxic and vasogenic edema causing increased ICP. Peak swelling typically at 48-72 hours post-injury.",0,4,10,B.c2,B.io,"Cerebral edema peaks at 3-5 days post-TBI. ICP monitoring is indicated for GCS <=8 with abnormal CT. Target ICP <22 mmHg and CPP 60-70 mmHg. Osmolar therapy (mannitol or hypertonic saline) is first-line for acute ICP crises.")
B.lA=new A.aw(63341,"MaterialIcons",!1)
B.asV=new A.ir("Early Post-Traumatic Seizures","Seizures occurring within 7 days of injury. Risk factors: GCS <10, cortical contusion, depressed skull fracture, SDH, EDH, penetrating injury.",0,2,7,B.fp,B.lA,"Seizure prophylaxis with levetiracetam or phenytoin is recommended for 7 days post-severe TBI (BTF guidelines). Early seizures do NOT predict late epilepsy. Phenytoin and levetiracetam are equally effective for early seizure prevention.")
B.asN=new A.ir("Paroxysmal Sympathetic Hyperactivity",'Episodic tachycardia, hypertension, tachypnea, diaphoresis, posturing, and hyperthermia. Previously called "sympathetic storming." Seen in severe DAI.',5,10,28,B.fo,B.lH,"PSH is diagnosed using the PSH-Assessment Measure (PSH-AM). Treatment ladder: remove noxious stimuli first, then gabapentin, propranolol, bromocriptine, and opioids. Dantrolene for severe posturing. Benzodiazepines can worsen cognitive recovery.")
B.a18=new A.aw(983988,"MaterialIcons",!1)
B.asQ=new A.ir("SIADH / Cerebral Salt Wasting","Hyponatremia from SIADH (euvolemic, fluid restrict) or CSW (hypovolemic, salt replace). Both cause Na <135, but volume status differs.",3,8,21,B.cn,B.a18,"Key distinction: SIADH = euvolemic/hypervolemic, low urine output, treat with fluid restriction. CSW = hypovolemic, high urine output, treat with isotonic or hypertonic saline replacement. Both cause concentrated urine and low serum Na. Check volume status and urine Na.")
B.asS=new A.ir("DVT / Pulmonary Embolism","Venous thromboembolism from immobility, hypercoagulable state, and endothelial injury. PE is a leading cause of preventable death in TBI.",3,10,90,B.y,B.ly,"Chemical DVT prophylaxis (LMWH or UFH) should start within 24-72 hours if hemorrhage is stable on repeat CT. Mechanical prophylaxis (SCDs) from admission. Screen with duplex ultrasound if high risk. IVC filter only when anticoagulation is absolutely contraindicated.")
B.asW=new A.ir("Late Post-Traumatic Seizures","Seizures occurring >7 days post-injury. Represents post-traumatic epilepsy. Risk increases with penetrating injury, SDH, and early seizures in some populations.",7,30,180,B.cG,B.lA,"Anticonvulsant prophylaxis beyond 7 days is NOT recommended (does not prevent epileptogenesis). If PTE develops, treat with standard AEDs (levetiracetam, lamotrigine, lacosamide preferred for fewer cognitive side effects). Risk of PTE: 2% mild, 5% moderate, 10-15% severe, 50% penetrating TBI.")
B.asR=new A.ir("Heterotopic Ossification","Abnormal bone formation in periarticular soft tissues, most commonly hip, elbow, shoulder, and knee. Causes pain and decreased ROM.",28,75,180,B.dy,B.lx,"HO screen with triple-phase bone scan (most sensitive early) or alkaline phosphatase. X-ray lags 4-6 weeks. Prophylaxis: indomethacin or etidronate in high-risk patients. Surgical excision only after maturation (18-24 months). Aggressive ROM does NOT cause HO but maintain gentle stretching.")
B.a13=new A.aw(983718,"MaterialIcons",!1)
B.asP=new A.ir("Posttraumatic Hydrocephalus","Communicating hydrocephalus from impaired CSF reabsorption. Presents as declining cognition, gait apraxia, and urinary incontinence (Hakim triad).",14,35,120,B.c3,B.a13,"Suspect PTH when a patient reaches a plateau then declines. Ventriculomegaly out of proportion to atrophy on CT/MRI. High-volume LP (30-50 mL) is both diagnostic and therapeutic -- if the patient improves, VP shunt is indicated. Risk factors: SAH, IVH, decompressive craniectomy.")
B.asO=new A.ir("Neuroendocrine Dysfunction","Pituitary dysfunction affecting GH, gonadotropins, ACTH, and/or TSH. Often under-recognized. Screen at 3 and 12 months.",30,90,180,B.ej,B.q0,"Pituitary dysfunction occurs in 25-50% of moderate-severe TBI. GH deficiency is most common, followed by gonadotropin deficiency. Screen with AM cortisol, TSH/free T4, testosterone/estradiol, IGF-1, and prolactin. GH stimulation testing is the gold standard for GH deficiency. Treat adrenal insufficiency before thyroid.")
B.a0J=new A.aw(63335,"MaterialIcons",!1)
B.asU=new A.ir("Spasticity","Velocity-dependent increase in muscle tone from upper motor neuron injury. Interferes with function, positioning, hygiene, and causes pain.",7,60,180,B.dx,B.a0J,"Treat spasticity only when it is functionally limiting -- some tone is beneficial (standing, transfers). Treatment ladder: stretching/positioning, oral agents (tizanidine, baclofen, dantrolene), botulinum toxin for focal spasticity, intrathecal baclofen for diffuse spasticity. Avoid benzodiazepines (sedation, cognitive impairment).")
B.qC=s([B.asT,B.asV,B.asN,B.asQ,B.asS,B.asW,B.asR,B.asP,B.asO,B.asU],A.aa("q<ir>"))
B.a64=s(["Cortical anatomy","Gyri and sulci","Coup-contrecoup sites","Brain topography"],t.s)
B.E_=new A.nj("Brain Realistic","Detailed realistic brain model for general neuroanatomy orientation. Useful for understanding gyri, sulci, and overall brain topography.","756bc05dd59e4f3ca1a93ffcc57a8994","pathophysiology",B.a64)
B.a6U=s(["Brainstem anatomy","Herniation syndromes","Reticular activating system","Disorders of consciousness"],t.s)
B.E0=new A.nj("Human Brain Cerebrum & Brainstem","Cerebrum and brainstem detail ideal for understanding herniation syndromes and disorders of consciousness pathways.","0aa0e33c5c854d1bab7bac9e1c7acaec","disorders-of-consciousness",B.a6U)
B.a69=s(["Frontal lobe function","Temporal lobe injuries","DAI predilection sites","Primary vs secondary injury"],t.s)
B.E1=new A.nj("Brain with Labeled Parts","Labeled brain model for learning lobes, functional areas, and key structures affected in TBI pathophysiology.","28c8971e11334e8b97a2a0d6235992e8","pathophysiology",B.a69)
B.a9w=s(["CT correlation","Hemorrhage locations","Marshall classification","Midline shift"],t.s)
B.DZ=new A.nj("Human Brain","Clean brain model well suited for neuroimaging correlation and understanding hemorrhage locations.","c9c9d4d671b94345952d012cc2ea7a24","neuroimaging",B.a9w)
B.a4r=s(["Frontal lobe concussion effects","Lobe-specific deficits","Acute management anatomy","Concussion biomechanics"],t.s)
B.DY=new A.nj("Human Brain - Detailed Lobes","Detailed lobe visualization for concussion education, understanding focal deficits, and acute management planning.","7a27c17fd6c0488bb31ab093236a47fb","concussion-mtbi",B.a4r)
B.a5f=s([B.E_,B.E0,B.E1,B.DZ,B.DY],A.aa("q<nj>"))
B.dE=new A.BW(0,"flowchart")
B.a0Y=new A.aw(983501,"MaterialIcons",!1)
B.a2l=new A.d2("icp-ladder","ICP Management Ladder","7-step escalation from HOB elevation through barbiturate coma","assets/infographics/flowcharts/icp_management_ladder.svg",B.dE,"acute-management",B.a0Y)
B.ij=new A.aw(62755,"MaterialIcons",!1)
B.a2k=new A.d2("agitation-algo","Agitation Management Algorithm","Decision tree for posttraumatic agitation with pharmacotherapy hierarchy","assets/infographics/flowcharts/agitation_management.svg",B.dE,"agitation-behavioral",B.ij)
