B.adO=new A.Dm(1,"evenOdd")
B.a6b=s([B.fZ,B.adO],A.aa("q<Dm>"))
B.a6f=s([-1,0,0,1,0,0,-1,0,1,0,0,0,-1,1,0,1,1,1,1,0],t.n)
B.a4Z=s(["GFAP (Glial Fibrillary Acidic Protein)",u.l,"S100B","Tau protein"],t.s)
B.aiu=new A.O("Which of the following blood biomarkers is specifically released from damaged astrocytes and serves as a marker of astrocyte activation in TBI?",B.a4Z,0,"GFAP is a protein found in the cytoskeleton of astrocytes and is released into the blood following glial cell injury or activation.","neuroimaging")
B.aaj=s(["GFAP < 30 pg/mL AND UCH-L1 < 360 pg/mL","GFAP > 30 pg/mL AND UCH-L1 < 360 pg/mL","GFAP < 30 pg/mL AND UCH-L1 > 360 pg/mL","GFAP > 30 pg/mL OR UCH-L1 > 360 pg/mL"],t.s)
B.afH=new A.O("According to the FDA-cleared thresholds for TBI blood biomarkers, which combination of results suggests that a head CT may be unnecessary due to a high negative predictive value (NPV)?",B.aaj,0,"When both biomarkers are below their respective FDA-cleared thresholds (Abbott i-STAT TBI plasma assay), the negative predictive value for an intracranial lesion is approximately 99.6%.","neuroimaging")
